function generateMermaid(tasks,depts) {
  if(!tasks.length) return "flowchart LR\n  A[Aucun processus encodée]";
  const lines=["flowchart TD","  %% Colona BPA"];
  Object.entries(PILLARS).forEach(([pk,pv])=>{
    const active=depts.filter(d=>d.pillar===pk&&tasks.find(t=>t.DeptID===d.id));
    if(!active.length) return;
    lines.push(`  subgraph ${pk}["${pv.icon} ${pv.label}"]`);
    active.forEach(d=>{
      const tl=tasks.filter(t=>t.DeptID===d.id);
      lines.push(`    ${d.id}["${d.name}\\n(${tl.length} tâche${tl.length>1?"s":""})"` + "]");
    });
    lines.push("  end");
  });
  const seen=new Set();
  tasks.forEach(t=>{
    (t.Deps||"").split(",").map(s=>s.trim()).filter(Boolean).forEach(did=>{
      const key=`${t.DeptID}->${did}`;
      if(!seen.has(key)&&t.DeptID!==did){seen.add(key);const l=t.TaskName.length>18?t.TaskName.slice(0,16)+"…":t.TaskName;lines.push(`  ${t.DeptID} -->|"${l}"| ${did}`);}
    });
  });
  return lines.join("\n");
}
function generateMermaidPillar(tasks,depts,pk) {
  const pd=depts.filter(d=>d.pillar===pk);
  const rel=tasks.filter(t=>pd.find(d=>d.id===t.DeptID));
  if(!rel.length) return `flowchart LR\n  A["Aucun processus pour ce pilier"]`;
  const lines=[`flowchart LR`,`  %% ${PILLARS[pk].label}`];
  pd.forEach(d=>{
    const ts=rel.filter(t=>t.DeptID===d.id);
    if(ts.length){
      lines.push(`  ${d.id}(["🔹 ${d.name}"])`);
      ts.forEach(t=>{const tid=`${d.id}_${t.TaskID}`;lines.push(`  ${tid}["${t.TaskName}\\n📅 ${t.Frequency}\\n💻 ${t.Softwares||"N/A"}"]`);lines.push(`  ${d.id} --> ${tid}`);});
    }
  });
  return lines.join("\n");
}

// ── SharePoint File Picker ─────────────────────────────────────────────────
function SharePointPicker({ value, onChange, msalConfig, msToken, onToken }) {
  const [mode, setMode] = useState("url"); // "url" | "browse"
  const [browsing, setBrowsing] = useState(false);
  const [files, setFiles] = useState([]);
  const [search, setSearch] = useState("");
  const [loadingFiles, setLoadingFiles] = useState(false);

  const isSpUrl = value && (value.includes("sharepoint.com") || value.includes("onedrive"));
  const fileName = value ? decodeURIComponent(value.split("/").pop().split("?")[0]) : "";

  const connectMicrosoft = async () => {
    if (!msalConfig?.clientId) { alert("Configure ton Azure Client ID dans Paramètres → SharePoint"); return; }
    setBrowsing(true);
    try {
      // Dynamic MSAL load
      if (!window.msal) {
        await new Promise((res,rej)=>{
          const s=document.createElement("script");
          s.src="https://alcdn.msauth.net/browser/2.38.3/js/msal-browser.min.js";
          s.onload=res; s.onerror=rej;
          document.head.appendChild(s);
        });
      }
      const msalInstance = new window.msal.PublicClientApplication({
        auth:{ clientId: msalConfig.clientId, authority:"https://login.microsoftonline.com/"+( msalConfig.tenantId||"common"), redirectUri: window.location.origin },
        cache:{ cacheLocation:"sessionStorage" }
      });
      await msalInstance.initialize();
      const resp = await msalInstance.loginPopup({ scopes:["Files.Read.All","Sites.Read.All","offline_access"] });
      onToken(resp.accessToken, msalInstance, resp.account);
    } catch(e) { alert("Erreur connexion Microsoft: "+e.message); setBrowsing(false); }
  };

  const loadFiles = async () => {
    if (!msToken) return;
    setLoadingFiles(true);
    try {
      const r = await fetch("https://graph.microsoft.com/v1.0/me/drive/root/children?$select=name,webUrl,file,folder&$top=50", {
        headers:{ Authorization:"Bearer "+msToken }
      });
      const d = await r.json();
      setFiles(d.value||[]);
    } catch {}
    setLoadingFiles(false);
  };

  useEffect(()=>{ if(msToken&&browsing) loadFiles(); },[msToken,browsing]);

  const S2 = {
    btn:(c,bg)=>({background:bg,color:c,border:`1.5px solid ${c}30`,borderRadius:7,padding:"8px 14px",cursor:"pointer",fontWeight:600,fontSize:12}),
    file:{padding:"8px 12px",borderRadius:7,cursor:"pointer",fontSize:12,display:"flex",alignItems:"center",gap:8,borderBottom:"1px solid #f0f0f0"},
  };

  if (browsing && msToken) return (
    <div style={{border:"1.5px solid #0078d4",borderRadius:8,overflow:"hidden"}}>
      <div style={{background:"#0078d4",padding:"8px 12px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{color:"#fff",fontWeight:700,fontSize:12}}>📁 SharePoint / OneDrive</span>
        <div style={{display:"flex",gap:6}}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Rechercher…" style={{padding:"3px 8px",borderRadius:5,border:"none",fontSize:12,width:160}}/>
          <button onClick={()=>setBrowsing(false)} style={{background:"rgba(255,255,255,0.2)",color:"#fff",border:"none",borderRadius:5,padding:"3px 8px",cursor:"pointer",fontSize:12}}>✕</button>
        </div>
      </div>
      <div style={{background:"#fff",maxHeight:200,overflowY:"auto"}}>
        {loadingFiles ? <div style={{padding:20,textAlign:"center",color:"#aaa",fontSize:12}}>Chargement…</div>
        : files.filter(f=>f.name.toLowerCase().includes(search.toLowerCase())).map(f=>(
          <div key={f.id||f.name} style={S2.file} onClick={()=>{onChange(f.webUrl);setBrowsing(false);}}>
            <span style={{fontSize:16}}>{f.folder?"📁":"📄"}</span>
            <span style={{flex:1}}>{f.name}</span>
            {!f.folder&&<span style={{color:"#0078d4",fontSize:11}}>Sélectionner</span>}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div>
      {value ? (
        <div style={{display:"flex",alignItems:"center",gap:8,padding:"8px 12px",background:isSpUrl?"#e8f4fd":"#f5f5f5",borderRadius:7,border:`1.5px solid ${isSpUrl?"#0078d4":"#ddd"}`}}>
          <span style={{fontSize:16}}>{isSpUrl?"☁️":"🔗"}</span>
          <a href={value} target="_blank" rel="noreferrer" style={{flex:1,color:"#0078d4",fontSize:12,textDecoration:"none",fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}} title={value}>{fileName||value}</a>
          <button onClick={()=>onChange("")} style={{background:"none",border:"none",color:"#aaa",cursor:"pointer",fontSize:14}}>✕</button>
          {msToken && <button onClick={()=>setBrowsing(true)} style={S2.btn("#0078d4","#e8f4fd")}>📁 Changer</button>}
        </div>
      ) : (
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          <div style={{display:"flex",gap:8}}>
            <input style={{flex:1,padding:"9px 12px",border:"1.5px solid #ddd",borderRadius:7,fontSize:13,background:"#fafafa"}} type="url" placeholder="Coller un lien SharePoint / URL…" value={value||""} onChange={e=>onChange(e.target.value)}/>
            {msToken
              ? <button onClick={()=>setBrowsing(true)} style={{...S2.btn("#fff","#0078d4"),whiteSpace:"nowrap"}}>📁 Parcourir SharePoint</button>
              : msalConfig?.clientId
                ? <button onClick={connectMicrosoft} style={{...S2.btn("#fff","#0078d4"),whiteSpace:"nowrap"}}><img src="https://img.icons8.com/color/16/microsoft.png" alt="" style={{verticalAlign:"middle",marginRight:4}}/>Connecter Microsoft</button>
                : <button onClick={()=>alert("Configure Azure Client ID dans ⚙️ Paramètres → SharePoint")} style={{...S2.btn("#666","#f0f0f0"),whiteSpace:"nowrap"}}>⚙️ Config SharePoint</button>
            }
          </div>
          <div style={{fontSize:11,color:"#aaa"}}>💡 Connecte ton compte Microsoft Colona pour parcourir SharePoint directement</div>
        </div>
      )}
    </div>
  );
}

// ── Multi-software selector ───────────────────────────────────────────────────
function SoftwareMultiSelector({ value, onChange, softwares, onSoftwareAdded, showSync }) {
  const selected=value?value.split(",").map(s=>s.trim()).filter(Boolean):[];
  const [showAdd,setShowAdd]=useState(false);
  const [newSw,setNewSw]=useState("");
  const [saving,setSaving]=useState(false);
  const toggle=(n)=>{const next=selected.includes(n)?selected.filter(s=>s!==n):[...selected,n];onChange(next.join(","));};
  const remove=(n)=>onChange(selected.filter(s=>s!==n).join(","));
  const handleAdd=async()=>{
    if(!newSw.trim())return;setSaving(true);
    try{const res=await apiAddSoftware(newSw.trim());if(res.status==="ok"){onSoftwareAdded({id:res.id,name:res.name});showSync("ok",`✅ "${res.name}" ajouté !`);toggle(res.name);setNewSw("");setShowAdd(false);}else if(res.status==="duplicate")showSync("error",`⚠️ "${newSw}" existe déjà.`);}
    catch{showSync("error","❌ Erreur.");}
    setSaving(false);
  };
  return (
    <div>
      {selected.length>0&&<div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:8}}>{selected.map(s=><span key={s} style={{background:"#005CA9",color:"#fff",borderRadius:16,padding:"3px 10px",fontSize:12,fontWeight:600,display:"flex",alignItems:"center",gap:5}}>💻 {s}<button onClick={()=>remove(s)} style={{background:"none",border:"none",color:"rgba(255,255,255,0.8)",cursor:"pointer",fontSize:13,padding:0}}>×</button></span>)}</div>}
      <div style={{display:"flex",flexWrap:"wrap",gap:5,padding:"10px 12px",border:"1.5px solid #ddd",borderRadius:7,background:"#fafafa",minHeight:44}}>
        {softwares.map(s=>{const a=selected.includes(s.name);return <button key={s.id} onClick={()=>toggle(s.name)} style={{padding:"4px 10px",borderRadius:16,border:`1.5px solid ${a?"#005CA9":"#ccc"}`,background:a?"#005CA9":"#fff",color:a?"#fff":"#555",fontSize:12,cursor:"pointer",fontWeight:a?700:400}}>{s.name}</button>;})}
        <button onClick={()=>setShowAdd(v=>!v)} style={{padding:"4px 12px",borderRadius:16,border:"1.5px dashed #D51317",background:"#fff8f8",color:"#D51317",fontSize:12,cursor:"pointer",fontWeight:600}}>+ Autre</button>
      </div>
      {showAdd&&<div style={{marginTop:8,display:"flex",gap:8}}><input value={newSw} onChange={e=>setNewSw(e.target.value)} placeholder="Nom du logiciel…" onKeyDown={e=>e.key==="Enter"&&handleAdd()} style={{flex:1,padding:"8px 12px",border:"1.5px solid #D51317",borderRadius:7,fontSize:13,outline:"none"}} autoFocus/><button onClick={handleAdd} disabled={saving||!newSw.trim()} style={{background:saving||!newSw.trim()?"#ccc":"#D51317",color:"#fff",border:"none",borderRadius:7,padding:"8px 14px",cursor:"pointer",fontWeight:700,fontSize:12}}>{saving?"…":"💾"}</button><button onClick={()=>{setShowAdd(false);setNewSw("");}} style={{background:"#f0f0f0",border:"none",borderRadius:7,padding:"8px 12px",cursor:"pointer"}}>✕</button></div>}
    </div>
  );
}
