                  <div style={{display:"flex",gap:8}}><input style={{...S.input,flex:1,border:`1.5px solid ${BRAND.orange}40`}} placeholder="https://mon-odoo.com/api/bpa/departments" value={odooUrl} onChange={e=>setOdooUrl(e.target.value)}/><button onClick={importFromOdoo} disabled={!odooUrl.trim()||odooLoading} style={{...S.btn(!odooUrl.trim()||odooLoading?"#ccc":BRAND.orange),whiteSpace:"nowrap"}}>{odooLoading?<><Spinner/>Import…</>:"⬇️ Importer"}</button></div>
